import numpy as np

class LearnedPositionalEmbedding:
    def __init__(self, max_positions, d_model, rng=None):
        if rng is None:
            rng = np.random.default_rng()
        self.max_positions = max_positions
        self.d_model = d_model
        self.weight = rng.normal(0, 0.02, (max_positions, d_model))

    def forward(self, seq_len):
        assert seq_len <= self.max_positions, f'seq_len {seq_len} > max_positions {self.max_positions}'
        return self.weight[:seq_len]

    def forward_indices(self, positions):
        return self.weight[positions]
